// ========================================
// EXTRAER DATOS DEL DM DE INSTAGRAM
// ========================================
const input = $input.first().json;
const body = input.body || input;

let senderPsid = '';
let messageText = '';
let messageId = '';
let timestamp = Date.now().toString();

try {
  const entry = body.entry?.[0];

  // Formato 1: messaging (Instagram DMs estándar)
  if (entry?.messaging?.[0]) {
    const msg = entry.messaging[0];
    senderPsid = msg.sender?.id || '';
    messageText = msg.message?.text || '';
    messageId = msg.message?.mid || '';
    timestamp = msg.timestamp || timestamp;
  }

  // Formato 2: changes (Webhook v2 / Instagram API)
  if (!messageText && entry?.changes?.[0]) {
    const change = entry.changes[0];
    const value = change.value || {};
    senderPsid = value.from?.id || value.sender?.id || '';
    messageText = value.message?.text || value.text || '';
    messageId = value.message?.mid || value.id || '';
    timestamp = value.timestamp || timestamp;
  }
} catch (e) {
  senderPsid = body.sender_id || body.from || '';
  messageText = body.message || body.text || '';
}

// Ignorar si no hay mensaje real (echo, delivery, etc)
if (!senderPsid || !messageText) {
  return [{ json: { skip: true, reason: 'no_valid_message' } }];
}

return [{
  json: {
    skip: false,
    sender_psid: senderPsid,
    message_text: messageText,
    message_id: messageId,
    timestamp: timestamp,
    source: 'instagram_dm'
  }
}];

// ========================================
// PREPARAR PAYLOAD PARA INSTAGRAM API
// ========================================
const senderPsid = $('🔍 Extraer Mensaje').first().json.sender_psid;
const aiResponse = $input.first().json.output || $input.first().json.text || 'Disculpa, hubo un problema. ¿Podés repetirme? 😊';

// Limpiar respuesta (quitar metadata accidental)
let cleanResponse = aiResponse
  .replace(/\[TEMPERATURA\]:.*/gi, '')
  .replace(/\[DOLOR\]:.*/gi, '')
  .replace(/\[INDUSTRIA\]:.*/gi, '')
  .replace(/\[NOMBRE\]:.*/gi, '')
  .replace(/CLASIFICACIÓN.*/gi, '')
  .replace(/^(assistant|aria):\s*/gi, '')
  .trim();

// Limitar largo para DM de Instagram (máx 1000 chars)
if (cleanResponse.length > 1000) {
  cleanResponse = cleanResponse.substring(0, 997) + '...';
}

// Detectar temperatura del lead
const msgLower = ($('🔍 Extraer Mensaje').first().json.message_text || '').toLowerCase();
let temperature = 'frio';
if (msgLower.includes('calendly') || msgLower.includes('agendar') || msgLower.includes('reunión') || msgLower.includes('disponibilidad')) {
  temperature = 'listo';
} else if (msgLower.includes('precio') || msgLower.includes('cuánto') || msgLower.includes('presupuesto') || msgLower.includes('urgente')) {
  temperature = 'caliente';
} else if (msgLower.includes('problema') || msgLower.includes('necesito') || msgLower.includes('ayuda') || msgLower.includes('automatizar')) {
  temperature = 'tibio';
}

return [{
  json: {
    sender_psid: senderPsid,
    response_text: cleanResponse,
    original_message: $('🔍 Extraer Mensaje').first().json.message_text,
    temperature: temperature,
    is_hot: (temperature === 'caliente' || temperature === 'listo'),
    timestamp: new Date().toISOString()
  }
}];

